import React from 'react';
import { ContactForm } from './ContactForm';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 id="form-heading" style={{ marginBottom: '1.5rem' }}>Contact Us</h1>
      <ContactForm />
    </div>
  );
}

import React, { useState, useRef } from 'react';
import './styles.css';

interface FormData {
  name: string;
  email: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  message?: string;
}

export const ContactForm: React.FC = () => {
  const [data, setData] = useState<FormData>({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitted, setSubmitted] = useState(false);

  // TODO: Add refs for focus management

  const validate = (): FormErrors => {
    const errs: FormErrors = {};
    if (!data.name.trim()) errs.name = 'Name is required';
    if (!data.email.trim() || !data.email.includes('@')) errs.email = 'Valid email is required';
    if (!data.message.trim()) errs.message = 'Message is required';
    return errs;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const errs = validate();
    setErrors(errs);
    if (Object.keys(errs).length > 0) {
      // TODO: Focus the first field with an error
      return;
    }
    setSubmitted(true);
  };

  if (submitted) {
    return <p data-testid="success-msg" className="form-success">Thank you for your message!</p>;
  }

  return (
    <form
      data-testid="contact-form"
      onSubmit={handleSubmit}
      noValidate
      // TODO: Add aria-labelledby
    >
      <div className="form-field">
        {/* TODO: Add <label> for name */}
        <input
          data-testid="field-name"
          className="form-input"
          value={data.name}
          onChange={e => setData(d => ({ ...d, name: e.target.value }))}
          placeholder="Your name"
          // TODO: Add id, aria-required, aria-invalid, aria-describedby
        />
        {errors.name && (
          <span data-testid="error-name" className="form-error">
            {/* TODO: Add role="alert" and id */}
            {errors.name}
          </span>
        )}
      </div>

      <div className="form-field">
        {/* TODO: Add <label> for email */}
        <input
          data-testid="field-email"
          className="form-input"
          type="email"
          value={data.email}
          onChange={e => setData(d => ({ ...d, email: e.target.value }))}
          placeholder="your@email.com"
          // TODO: Add id, aria-required, aria-invalid, aria-describedby
        />
        {errors.email && (
          <span data-testid="error-email" className="form-error">
            {errors.email}
          </span>
        )}
      </div>

      <div className="form-field">
        {/* TODO: Add <label> for message */}
        <textarea
          data-testid="field-message"
          className="form-input form-textarea"
          value={data.message}
          onChange={e => setData(d => ({ ...d, message: e.target.value }))}
          placeholder="Your message"
          rows={4}
          // TODO: Add id, aria-required, aria-invalid, aria-describedby
        />
        {errors.message && (
          <span data-testid="error-message" className="form-error">
            {errors.message}
          </span>
        )}
      </div>

      <button data-testid="submit-btn" className="form-submit" type="submit">Send Message</button>
    </form>
  );
};

.form-field {
  margin-bottom: 1rem;
}

.form-field label {
  display: block;
  margin-bottom: 0.25rem;
  font-size: 0.875rem;
  font-weight: 500;
  color: #374151;
}

.form-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  font-family: inherit;
}

.form-input:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
  border-color: #3b82f6;
}

.form-textarea {
  resize: vertical;
}

.form-error {
  display: block;
  margin-top: 0.25rem;
  font-size: 0.75rem;
  color: #dc2626;
}

.form-submit {
  padding: 0.625rem 1.5rem;
  background: #3b82f6;
  color: white;
  border: none;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
}

.form-submit:hover {
  background: #2563eb;
}

.form-submit:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}

.form-success {
  padding: 1.5rem;
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  border-radius: 0.5rem;
  color: #166534;
  text-align: center;
  font-weight: 500;
}

