import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Accessible Form Labels', () => {
  it('each input has an associated label', () => {
    render(<App />);
    const nameInput = screen.getByTestId('field-name');
    const emailInput = screen.getByTestId('field-email');
    const messageInput = screen.getByTestId('field-message');
    expect(nameInput.id).toBeTruthy();
    expect(emailInput.id).toBeTruthy();
    expect(messageInput.id).toBeTruthy();
    expect(document.querySelector(`label[for="${nameInput.id}"]`)).toBeInTheDocument();
    expect(document.querySelector(`label[for="${emailInput.id}"]`)).toBeInTheDocument();
    expect(document.querySelector(`label[for="${messageInput.id}"]`)).toBeInTheDocument();
  });

  it('required fields have aria-required', () => {
    render(<App />);
    expect(screen.getByTestId('field-name')).toHaveAttribute('aria-required', 'true');
    expect(screen.getByTestId('field-email')).toHaveAttribute('aria-required', 'true');
    expect(screen.getByTestId('field-message')).toHaveAttribute('aria-required', 'true');
  });

  it('shows aria-invalid on error fields after submit', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('field-name')).toHaveAttribute('aria-invalid', 'true');
    expect(screen.getByTestId('field-email')).toHaveAttribute('aria-invalid', 'true');
  });

  it('error messages are linked via aria-describedby', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('submit-btn'));
    const nameInput = screen.getByTestId('field-name');
    const describedBy = nameInput.getAttribute('aria-describedby');
    expect(describedBy).toBeTruthy();
    const errorEl = document.getElementById(describedBy!);
    expect(errorEl).toBeInTheDocument();
    expect(errorEl?.textContent).toBeTruthy();
  });

  it('error messages have role alert', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('error-name')).toHaveAttribute('role', 'alert');
  });

  it('form has aria-labelledby', () => {
    render(<App />);
    const form = screen.getByTestId('contact-form');
    expect(form).toHaveAttribute('aria-labelledby', 'form-heading');
  });

  it('submits successfully with valid data', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'alice@test.com' } });
    fireEvent.change(screen.getByTestId('field-message'), { target: { value: 'Hello!' } });
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('success-msg')).toBeInTheDocument();
  });
});

