import React, { useState, useRef } from 'react';
import './styles.css';

interface FormData {
  name: string;
  email: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  message?: string;
}

export const ContactForm: React.FC = () => {
  const [data, setData] = useState<FormData>({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitted, setSubmitted] = useState(false);

  const nameRef = useRef<HTMLInputElement>(null);
  const emailRef = useRef<HTMLInputElement>(null);
  const messageRef = useRef<HTMLTextAreaElement>(null);

  const validate = (): FormErrors => {
    const errs: FormErrors = {};
    if (!data.name.trim()) errs.name = 'Name is required';
    if (!data.email.trim() || !data.email.includes('@')) errs.email = 'Valid email is required';
    if (!data.message.trim()) errs.message = 'Message is required';
    return errs;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const errs = validate();
    setErrors(errs);
    if (Object.keys(errs).length > 0) {
      if (errs.name) nameRef.current?.focus();
      else if (errs.email) emailRef.current?.focus();
      else if (errs.message) messageRef.current?.focus();
      return;
    }
    setSubmitted(true);
  };

  if (submitted) {
    return <p data-testid="success-msg" className="form-success">Thank you for your message!</p>;
  }

  return (
    <form
      data-testid="contact-form"
      onSubmit={handleSubmit}
      noValidate
      aria-labelledby="form-heading"
    >
      <div className="form-field">
        <label htmlFor="name-input">Name</label>
        <input
          ref={nameRef}
          id="name-input"
          data-testid="field-name"
          className="form-input"
          value={data.name}
          onChange={e => setData(d => ({ ...d, name: e.target.value }))}
          placeholder="Your name"
          aria-required="true"
          aria-invalid={!!errors.name}
          aria-describedby={errors.name ? 'error-name-id' : undefined}
        />
        {errors.name && (
          <span data-testid="error-name" id="error-name-id" className="form-error" role="alert">
            {errors.name}
          </span>
        )}
      </div>

      <div className="form-field">
        <label htmlFor="email-input">Email</label>
        <input
          ref={emailRef}
          id="email-input"
          data-testid="field-email"
          className="form-input"
          type="email"
          value={data.email}
          onChange={e => setData(d => ({ ...d, email: e.target.value }))}
          placeholder="your@email.com"
          aria-required="true"
          aria-invalid={!!errors.email}
          aria-describedby={errors.email ? 'error-email-id' : undefined}
        />
        {errors.email && (
          <span data-testid="error-email" id="error-email-id" className="form-error" role="alert">
            {errors.email}
          </span>
        )}
      </div>

      <div className="form-field">
        <label htmlFor="message-input">Message</label>
        <textarea
          ref={messageRef}
          id="message-input"
          data-testid="field-message"
          className="form-input form-textarea"
          value={data.message}
          onChange={e => setData(d => ({ ...d, message: e.target.value }))}
          placeholder="Your message"
          rows={4}
          aria-required="true"
          aria-invalid={!!errors.message}
          aria-describedby={errors.message ? 'error-message-id' : undefined}
        />
        {errors.message && (
          <span data-testid="error-message" id="error-message-id" className="form-error" role="alert">
            {errors.message}
          </span>
        )}
      </div>

      <button data-testid="submit-btn" className="form-submit" type="submit">Send Message</button>
    </form>
  );
};
